parameters.jsCode:
const tg = $input.first().json;
const msg = tg.message || tg.edited_message;
if (!msg) return [];
const text = (msg.text || msg.caption || '').trim();
if (!text || (msg.from && msg.from.is_bot)) return [];
const from = msg.from || {};
return [{ json: {
  tg_chat_id: String(msg.chat.id),
  message_text: text,
  name: [from.first_name, from.last_name].filter(Boolean).join(' ') || 'Гость',
  language: from.language_code || 'ru'
}}];

const ctx = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const extracted = $('📝 Извлечь').first().json;

// Дата — единственное, что считает код. Всё остальное — данные из базы.
const currentDate = new Date().toLocaleDateString('ru-RU', {day:'numeric', month:'long', year:'numeric'});

// Память о клиенте
const lines = [];
if (ctx?.client_name) lines.push(`Имя: ${ctx.client_name}`);
if (ctx?.client_stage && ctx.client_stage !== 'new') lines.push(`Стадия: ${ctx.client_stage}`);
if (ctx?.client_country) lines.push(`Откуда: ${ctx.client_country}`);
if (ctx?.interests?.length) lines.push(`Интересы: ${ctx.interests.join(', ')}`);
if (ctx?.budget_level && ctx.budget_level !== 'medium') lines.push(`Бюджет: ${ctx.budget_level}`);
if (ctx?.travel_style) lines.push(`Стиль: ${ctx.travel_style}`);
if (ctx?.arrival_date) lines.push(`Дата приезда: ${ctx.arrival_date}`);
if (ctx?.group_size) lines.push(`Группа: ${ctx.group_size} чел.`);
if (ctx?.has_children) lines.push('Едут с детьми: да');
if (ctx?.last_tour_viewed) lines.push(`Смотрел тур: ${ctx.last_tour_viewed}`);
if (ctx?.tours_booked?.length) lines.push(`Забронировал: ${ctx.tours_booked.join(', ')}`);
const clientMemory = lines.length ? lines.join('\n') : 'Новый гость, ничего не знаем.';

// История диалога
let lastConvs = 'Первое обращение.';
let convs = ctx?.last_conversations || [];
if (typeof convs === 'string') { try { convs = JSON.parse(convs); } catch { convs = []; } }
if (Array.isArray(convs) && convs.length) {
  lastConvs = convs.slice(0, 8).reverse()
    .map(c => `Клиент: ${c.msg || ''}\nКотЭ: ${c.res || ''}`).join('\n---\n');
}

// Туры — компактные строки для промпта
const tours = (ctx?.tours_catalog || [])
  .map(t => `[${t.city}] ${t.t} — ${t.price}฿${t.child ? ` (дети ${t.child}฿)` : ''}${t.dur ? `, ${t.dur}` : ''}${t.season ? ` ⚠️ ${t.season}` : ''} | start=${t.slug}`)
  .join('\n') || 'Каталог временно пуст — отправь к менеджеру.';

// Знания под вопрос
const knowledge = (ctx?.knowledge_pack || [])
  .map(k => `• ${k.t} [${k.city}]: ${k.c}${k.tip ? `\n  💡 ${k.tip}` : ''}`)
  .join('\n') || 'Под этот вопрос знаний не нашлось — отвечай аккуратно, без выдумок.';

return [{ json: {
  tg_chat_id: extracted.tg_chat_id,
  message_text: extracted.message_text,
  client_id: ctx?.client_id ?? null,
  client_name: ctx?.client_name ?? null,
  client_stage: ctx?.client_stage || 'new',
  is_new_client: ctx?.is_new_client || false,
  current_date: currentDate,
  client_memory: clientMemory,
  last_conversations: lastConvs,
  tours_catalog: tours,
  knowledge_pack: knowledge
}}];

const ai = $input.first().json;
const prev = $('✍️ Собрать промпт').first().json;
let reply = 'Извините, что-то пошло не так. Попробуйте через минуту 🙏';
try {
  if (ai.error) {
    const code = ai.error.code || ai.error.status || '';
    if (code === 429 || String(code).includes('RESOURCE_EXHAUSTED')) {
      reply = 'Секунду, немного перегружен — напишите ещё раз через минуту 🙏';
    } else if (code === 401 || code === 403) {
      reply = 'Технические неполадки, уже разбираемся!';
    } else if (code === 500 || code === 503) {
      reply = 'Временные неполадки с ИИ. Попробуйте через пару минут 🙏';
    } else {
      reply = 'Что-то пошло не так. Попробуйте ещё раз 🙏';
    }
  } else {
    const text = ai.candidates?.[0]?.content?.parts?.[0]?.text;
    if (text && text.trim()) reply = text.trim();
  }
} catch(e) {}
return [{ json: { ...prev, ai_reply: reply } }];

const d = $input.first().json;
const text = (d.message_text || '').toLowerCase();

// Interests detection
const interests = [];
if (/остров|море|пляж|пхи|симил|джеймс|снорклинг|яхт|морск|дайв|кораллы|плавани/i.test(text)) interests.push('islands');
if (/актив|рафтинг|atv|квадро|мото|зиплайн|гиббон|слон|адренал|спорт|экстрим/i.test(text)) interests.push('active');
if (/природ|джунгли|као.*сок|водопад|лес|нацпарк|эко|нетронут/i.test(text)) interests.push('nature');
if (/вечер|шоу|фаер|тиффани|муай|бокс|закат|романтик|ужин|кабаре/i.test(text)) interests.push('evening');
if (/дети|ребенок|семья|детей|малыш|семейн|ребята|ребёнок/i.test(text)) interests.push('family');
if (/vip|яхта|премиум|luxury|эксклюзив|персональн/i.test(text)) interests.push('vip');

// Budget signals
let budget = null;
if (/недорого|дёшево|бюджетн|экономн|сколько стоит.*самый/i.test(text)) budget = 'low';
if (/vip|не.*дорог|деньги.*не.*вопрос|любой бюджет|премиум/i.test(text)) budget = 'vip';

// Arrival date extraction (month names)
let arrivalDate = null;
const months = [
  ['январ', '01'], ['феврал', '02'], ['март', '03'], ['апрел', '04'],
  ['май', '05'], ['мая', '05'], ['июн', '06'], ['июл', '07'],
  ['август', '08'], ['сентябр', '09'], ['октябр', '10'], ['ноябр', '11'], ['декабр', '12']
];
for (const [name, num] of months) {
  if (text.includes(name)) {
    const year = num >= '11' ? '2026' : '2027';
    arrivalDate = `${year}-${num}`;
    break;
  }
}
// Also catch "через N дней/недель"
if (!arrivalDate && /через (\d+) (день|дня|дней|недел)/i.test(text)) {
  const match = text.match(/через (\d+) (день|дня|дней|недел)/i);
  const days = parseInt(match[1]) * (match[2].startsWith('недел') ? 7 : 1);
  const arrival = new Date();
  arrival.setDate(arrival.getDate() + days);
  arrivalDate = arrival.toISOString().slice(0, 7);
}

// Group size extraction
let groupSize = null;
let hasChildren = null;
const groupMatch = text.match(/нас\s+(\d+)|([двое|трое|четверо|пятеро])|([\d]+)\s*человек|([\d]+)\s*взросл/);
if (groupMatch) {
  const wordNums = { 'двое': 2, 'трое': 3, 'четверо': 4, 'пятеро': 5 };
  groupSize = parseInt(groupMatch[1] || groupMatch[3] || groupMatch[4]) || wordNums[groupMatch[2]] || null;
}
if (/дети|ребенок|ребёнок|детей|малыш|с детьми|ребята/i.test(text)) hasChildren = true;
if (/без детей|только взросл|не берём детей/i.test(text)) hasChildren = false;

// Stage detection
let stage = null;
if (/забронир|оформ|хочу.*(тур|брон)|запис|оплат|купить|давай|беру|берём|пишите цену|как заброн/i.test(text)) {
  stage = 'booking';
} else if (/понравил|отлично|супер|класс|незабываем|рекомендую|спасибо за тур|было здорово/i.test(text)) {
  stage = 'done';
} else if (/потом|подумаю|позже|не сейчас|может быть|посмотрим|пока не знаю/i.test(text)) {
  stage = 'thinking';
} else if (/не нужно|не надо|не интересно|нет спасибо|передумал|отменить/i.test(text)) {
  stage = 'cold';
} else if (interests.length || budget || arrivalDate || groupSize) {
  stage = 'interest';
}

// Tour viewed
let lastTour = null;
const tourMap = [
  [/джеймс.*бонд|james.*bond|бонд.*остров/i, 'james'],
  [/пхи.пхи|phi.phi/i, 'phiphi-bamboo'],
  [/симилан/i, 'similan'],
  [/мото.?тур|мотоцикл.*остров/i, 'moto'],
  [/рафтинг|слоны.*atv|atv.*слон/i, 'raft'],
  [/гиббон|зиплайн/i, 'gibbon'],
  [/као.*сок/i, 'khaosok2'],
  [/яхт/i, 'yacht'],
  [/vip.*сопров|персональный.*менеджер/i, 'vip'],
  [/фаер.*шоу|fire.*show/i, 'fire'],
  [/ко.*лан|ko.*lan/i, 'kolan'],
  [/тиффани/i, 'tiffany'],
  [/нонг.*нуч/i, 'nong-nooch'],
  [/рамаян|аквапарк/i, 'aqua-ramayana'],
  [/катамаран|закат/i, 'sunset-cat'],
  [/кхао.*кхео|сафари/i, 'khao-kheo'],
];
for (const [re, slug] of tourMap) {
  if (re.test(text)) { lastTour = slug; break; }
}

return [{ json: {
  client_id: d.client_id,
  tg_chat_id: d.tg_chat_id,
  client_stage: d.client_stage,
  interests: interests.length ? interests : null,
  budget_level: budget,
  new_stage: stage,
  last_tour_viewed: lastTour,
  arrival_date: arrivalDate,
  group_size: groupSize,
  has_children: hasChildren,
  has_updates: !!(interests.length || budget || lastTour || arrivalDate || groupSize || hasChildren !== null),
  has_stage_update: !!stage
}}];

